// AMD module for the mod_fastpix activity edit form upload widget.
// AMD-wrapped by hand since the dev environment lacks grunt amd.
// Replace via `grunt amd` once available.
//
// Phase C unified panel:
// - Single panel with drop zone + URL row at once (no pill toggle).
// - File drop or click sets source_type='upload' and auto-starts upload.
// - URL Upload button sets source_type='urlpull' and calls validate.

define(['core/ajax', 'core/notification', 'core/templates'], function(Ajax, Notification, Templates) {
    'use strict';

    // FastPix resumable upload SDK — npm: @fastpix/resumable-uploads.
    // Loaded via native ESM import() — bypasses Moodle's RequireJS like
    // the player ESM in view.php. Requires local_fastpix v >= 2026051201
    // (sends X-Client-Type: web-browser so FastPix returns a POST-signed
    // resumable URL the SDK can use). 16 MB chunks, 5 retries.
    var UPLOAD_SDK_URL        = 'https://cdn.jsdelivr.net/npm/@fastpix/resumable-uploads@latest/+esm';
    var UPLOAD_CHUNK_KB       = 16384;
    var UPLOAD_CHUNK_ATTEMPTS = 5;

    var SELECTORS = {
        region:           '[data-region="fastpix-upload-widget"]',
        picker:           '[data-region="fastpix-upload-picker"]',
        dropzone:         '[data-region="fastpix-upload-dropzone"]',
        input:            '[data-region="fastpix-upload-input"]',
        browseLink:       '[data-action="fastpix-browse-trigger"]',
        progressWrap:     '[data-region="fastpix-upload-progress"]',
        progressBar:      '[data-region="fastpix-upload-bar"]',
        progressBarFill:  '[data-region="fastpix-upload-bar-fill"]',
        progressPct:      '[data-region="fastpix-upload-percent"]',
        status:           '[data-region="fastpix-upload-status"]',
        urlStatus:        '[data-region="fastpix-urlpull-status"]',
        sourceType:       '[name="source_type"]',
        sourceUrl:        '[name="source_url"]',
        validateBtn:      '[name="validate_url"]'
    };

    var sessionField = null;
    var widgetRegion = null;
    // Course context id from init() — forwarded to local_fastpix upload web
    // services so they check mod/fastpix:uploadmedia at the course context.
    var widgetContextId = null;

    // Read the Media-settings fields into the create_upload_session args.
    // local_fastpix consumes: contextid, title (required), accesspolicy
    // (required), captionsmode, languagecode — NOT filename/size.
    var gatherUploadArgs = function(file) {
        var nameEl = document.querySelector('input[name="name"]');
        var title = nameEl && nameEl.value ? nameEl.value.trim() : '';
        if (!title) {
            title = file && file.name ? file.name.replace(/\.[^.]+$/, '') : 'Untitled video';
        }
        var apEl = document.querySelector('input[name="access_policy"]:checked');
        var accesspolicy = apEl ? apEl.value : 'private';
        var captionsmode = 'none';
        if (document.querySelector('input[name="captionsenabled"]:checked')) {
            var modeEl = document.querySelector('input[name="captionsmode"]:checked');
            captionsmode = (modeEl && modeEl.value === 'vtt') ? 'vtt' : 'auto';
        }
        var langEl = document.querySelector('select[name="languagecode"]');
        var languagecode = (captionsmode === 'auto' && langEl) ? langEl.value : '';
        return {
            contextid: widgetContextId,
            title: title,
            accesspolicy: accesspolicy,
            captionsmode: captionsmode,
            languagecode: languagecode
        };
    };

    var setSourceType = function(value) {
        var el = document.querySelector(SELECTORS.sourceType);
        if (!el) { return; }
        el.value = value;
        el.dispatchEvent(new Event('change', {bubbles: true}));
    };

    var setStatus = function(message, kind) {
        if (!widgetRegion) { return; }
        var el = widgetRegion.querySelector(SELECTORS.status);
        if (!el) { return; }
        el.hidden = false;
        el.textContent = message;
        el.className = 'mt-3 small alert alert-' + kind;
    };

    var clearStatus = function() {
        if (!widgetRegion) { return; }
        var el = widgetRegion.querySelector(SELECTORS.status);
        if (!el) { return; }
        el.hidden = true;
        el.textContent = '';
        el.className = 'mt-3 small';
    };

    var setUrlStatus = function(message, kind) {
        var el = document.querySelector(SELECTORS.urlStatus);
        if (!el) { return; }
        if (!message) {
            el.textContent = '';
            el.className = 'fastpix-vs-url-status';
            return;
        }
        var state = kind === 'success' ? 'success'
                  : kind === 'danger'  ? 'danger'
                  : kind === 'warning' ? 'warning'
                  : 'muted';
        el.textContent = message;
        el.className = 'fastpix-vs-url-status fastpix-vs-url-status--' + state;
    };

    // Lazy ESM-import the FastPix resumable upload SDK. Static factory
    // Uploader.init(opts) — wrap in createUpload(opts) adapter.
    var loadUploadSdk = function() {
        if (window.__fastpixUploadSdk) {
            return Promise.resolve(window.__fastpixUploadSdk);
        }
        return import(UPLOAD_SDK_URL).then(function(mod) {
            if (!mod.Uploader || typeof mod.Uploader.init !== 'function') {
                throw new Error('upload_sdk_no_init');
            }
            var adapter = {
                createUpload: function(opts) { return mod.Uploader.init(opts); }
            };
            window.__fastpixUploadSdk = adapter;
            return adapter;
        });
    };

    // Resumable + chunked upload via @fastpix/resumable-uploads.
    var putToSignedUrl = function(file, uploadUrl, onProgress) {
        return loadUploadSdk().then(function(sdk) {
            return new Promise(function(resolve, reject) {
                var upload = sdk.createUpload({
                    endpoint:          uploadUrl,
                    file:              file,
                    chunkSize:         UPLOAD_CHUNK_KB,
                    retryChunkAttempt: UPLOAD_CHUNK_ATTEMPTS
                });
                upload.on('progress', function(event) {
                    // FastPix SDK reports % at event.detail.progress (0..100),
                    // not event.detail (which is an object → NaN → stuck at 0%).
                    var raw = (event && event.detail && typeof event.detail.progress === 'number')
                        ? event.detail.progress
                        : 0;
                    var pct = Math.max(0, Math.min(100, Math.round(raw)));
                    onProgress(pct);
                });
                upload.on('success', function() {
                    onProgress(100);
                    resolve();
                });
                upload.on('error', function(event) {
                    var detail = event.detail || {};
                    var msg = detail.message || (detail.toString && detail.toString()) || 'upload_failed';
                    reject(new Error(msg));
                });
            });
        }, function(err) {
            if (window.console) {
                console.error('[mod_fastpix] failed to load upload SDK', err);
            }
            throw new Error('upload_sdk_load_failed');
        });
    };

    var showProgressUI = function() {
        if (!widgetRegion) { return; }
        // Keep the upload dropzone visible during upload — just reveal progress.
        var progress = widgetRegion.querySelector(SELECTORS.progressWrap);
        if (progress) { progress.hidden = false; }
    };

    var showSuccessUI = function() {
        if (!widgetRegion) { return; }
        var progress = widgetRegion.querySelector(SELECTORS.progressWrap);
        if (progress) { progress.hidden = true; }
        // Show just the completion state — not the filename.
        setStatus('Upload complete. Save the activity to finalise.', 'success');
    };

    var showDropzoneUI = function() {
        if (!widgetRegion) { return; }
        var dropzone = widgetRegion.querySelector(SELECTORS.dropzone);
        if (dropzone) { dropzone.hidden = false; }
        var progress = widgetRegion.querySelector(SELECTORS.progressWrap);
        if (progress) { progress.hidden = true; }
    };

    var handleFileSelected = function(file) {
        if (!file || !widgetRegion) { return; }
        setSourceType('upload');
        clearStatus();
        showProgressUI();

        Ajax.call([{
            methodname: 'local_fastpix_create_upload_session',
            args: gatherUploadArgs(file)
        }])[0].then(function(session) {
            var bar = widgetRegion.querySelector(SELECTORS.progressBar);
            var fill = widgetRegion.querySelector(SELECTORS.progressBarFill);
            var pct = widgetRegion.querySelector(SELECTORS.progressPct);
            // create_upload_session returns no-underscore fields 'uploadurl' /
            // 'uploadid' (differs from create_url_pull_session's 'upload_url' /
            // 'session_id').
            return putToSignedUrl(file, session.uploadurl, function(percent) {
                if (bar) { bar.value = percent; }
                if (fill) { fill.style.width = percent + '%'; }
                if (pct) { pct.textContent = percent + '%'; }
            }).then(function() {
                if (sessionField) {
                    sessionField.value = String(session.session_id || session.uploadid || '');
                }
                showSuccessUI();
            });
        }).catch(function(e) {
            showDropzoneUI();
            setStatus('Upload failed: ' + (e.message || 'unknown error'), 'danger');
            Notification.exception(e);
        });
    };

    var wireDropzone = function() {
        if (!widgetRegion) { return; }
        var dropzone = widgetRegion.querySelector(SELECTORS.dropzone);
        var input = widgetRegion.querySelector(SELECTORS.input);
        var browse = widgetRegion.querySelector(SELECTORS.browseLink);
        if (!dropzone || !input) { return; }

        if (browse) {
            browse.addEventListener('click', function(e) {
                e.preventDefault();
                input.click();
            });
        }

        dropzone.addEventListener('click', function(e) {
            if (e.target === input || e.target === browse) { return; }
            input.click();
        });

        dropzone.addEventListener('keydown', function(e) {
            if (e.key === 'Enter' || e.key === ' ') {
                e.preventDefault();
                input.click();
            }
        });

        var setDragging = function(on) {
            if (on) {
                dropzone.classList.add('is-dragging');
            } else {
                dropzone.classList.remove('is-dragging');
            }
        };

        ['dragenter', 'dragover'].forEach(function(ev) {
            dropzone.addEventListener(ev, function(e) {
                e.preventDefault();
                e.stopPropagation();
                setDragging(true);
            });
        });
        ['dragleave', 'dragend'].forEach(function(ev) {
            dropzone.addEventListener(ev, function(e) {
                e.preventDefault();
                e.stopPropagation();
                setDragging(false);
            });
        });
        dropzone.addEventListener('drop', function(e) {
            e.preventDefault();
            e.stopPropagation();
            setDragging(false);
            var file = e.dataTransfer && e.dataTransfer.files && e.dataTransfer.files[0];
            if (file) {
                handleFileSelected(file);
            }
        });

        input.addEventListener('change', function() {
            var file = input.files && input.files[0];
            if (file) {
                handleFileSelected(file);
            }
        });
    };

    var validateUrl = function(button) {
        var urlInput = document.querySelector(SELECTORS.sourceUrl);
        if (!urlInput || !urlInput.value) {
            setUrlStatus('Enter a URL first.', 'warning');
            return;
        }
        setSourceType('urlpull');
        setUrlStatus('Uploading…', 'muted');
        if (button) { button.disabled = true; }

        Ajax.call([{
            methodname: 'local_fastpix_create_url_pull_session',
            args: { source_url: urlInput.value, contextid: widgetContextId }
        }])[0].then(function(session) {
            if (sessionField) {
                sessionField.value = String(session.session_id);
            }
            setUrlStatus('✓ URL accepted. Save the activity to finalise.', 'success');
            if (button) { button.disabled = false; }
        }).catch(function(e) {
            Notification.exception(e);
            setUrlStatus('URL rejected.', 'danger');
            if (button) { button.disabled = false; }
        });
    };

    var attachValidateHandler = function() {
        var validateBtn = document.querySelector(SELECTORS.validateBtn);
        if (!validateBtn) { return false; }
        if (validateBtn.getAttribute('data-fastpix-wired') === '1') { return true; }
        validateBtn.setAttribute('data-fastpix-wired', '1');
        validateBtn.addEventListener('click', function(e) {
            e.preventDefault();
            validateUrl(validateBtn);
        });
        return true;
    };

    var attachUrlInputInvalidate = function() {
        var urlInput = document.querySelector(SELECTORS.sourceUrl);
        if (!urlInput) { return false; }
        if (urlInput.getAttribute('data-fastpix-wired') === '1') { return true; }
        urlInput.setAttribute('data-fastpix-wired', '1');
        urlInput.addEventListener('input', function() {
            if (sessionField) { sessionField.value = ''; }
            setUrlStatus('', 'muted');
        });
        return true;
    };

    return {
        init: function(config) {
            widgetContextId = config.contextId;
            sessionField = document.querySelector('input[name="' + config.fieldnameSession + '"]');
            widgetRegion = document.querySelector(SELECTORS.region);

            // Pre-render attempt (in case the validate button / URL input exist
            // outside the rendered widget DOM — defensive).
            attachValidateHandler();
            attachUrlInputInvalidate();

            if (!widgetRegion) { return; }

            Templates.renderForPromise('mod_fastpix/upload_widget', {}).then(function(result) {
                Templates.replaceNodeContents(widgetRegion, result.html, result.js);
                attachValidateHandler();
                attachUrlInputInvalidate();
                wireDropzone();
                return null;
            }).catch(function(e) {
                Notification.exception(e);
            });
        }
    };
});
